# Natural scene - a forest clearing
# Player stands at the south of the meadow, facing north

(player x=0 y=1.8 z=-10 yaw=0)

# === Ground ===
(box x=0 y=-0.05 z=0 sx=150 sy=0.1 sz=150 mat='grass_01')

# Dirt patches (exposed soil)
(box x=6 y=0.01 z=3 sx=5 sy=0.02 sz=4 ra=20 mat='dirt_01')
(box x=-8 y=0.01 z=10 sx=4 sy=0.02 sz=6 ra=-15 mat='dirt_01')
(box x=15 y=0.01 z=-5 sx=3 sy=0.02 sz=3 ra=35 mat='dirt_01')

# Sandy path running north from the player through the clearing
(box x=0 y=0.01 z=0 sx=2.5 sy=0.02 sz=20 mat='sand_01')

# === Rolling Hills ===
# Each is a wide flattened sphere, mostly underground, tip rising above grass.
# Scale = full diameter. Rise = center_y + sy/2.

# Hill NW — rises ~4m, very wide
(sphere x=-32 y=-6 z=28 sx=52 sy=20 sz=44 mat='grass_01')

# Hill NE — rises ~3m
(sphere x=36 y=-5 z=22 sx=38 sy=16 sz=32 mat='grass_01')

# Hill far north — the tallest, rises ~5m, frames the clearing
(sphere x=2 y=-7 z=42 sx=50 sy=24 sz=46 mat='grass_01')

# Gentle rise to the south — subtle
(sphere x=-5 y=-4 z=-32 sx=34 sy=12 sz=30 mat='grass_01')

# === Trees ===
# Small tree:  trunk sy=4, canopy s=4, canopy center y=4+2=6
# Medium tree: trunk sy=5, canopy s=5, canopy center y=5+2.5=7.5
# Large tree:  trunk sy=7, canopy s=7, canopy center y=7+3.5=10.5

